import{_ as d,C as c,o,c as p,a2 as a,b as n,w as t,a as i,E as r,a3 as l}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"Claude Code — Agentic Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/claude-code/agentic-loop.md","filePath":"research/agents/claude-code/agentic-loop.md"}'),h={name:"research/agents/claude-code/agentic-loop.md"};function u(g,e,b,m,f,y){const s=c("Mermaid");return o(),p("div",null,[e[2]||(e[2]=a('<h1 id="claude-code-—-agentic-loop" tabindex="-1">Claude Code — Agentic Loop <a class="header-anchor" href="#claude-code-—-agentic-loop" aria-label="Permalink to &quot;Claude Code — Agentic Loop&quot;">​</a></h1><blockquote><p>How Claude Code&#39;s agentic execution loop works, based on official documentation and observable behavior.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Claude Code&#39;s core execution model is a <strong>three-phase agentic loop</strong>: gather context → take action → verify results. These phases blend together fluidly — Claude uses tools throughout, whether searching files to understand code, editing to make changes, or running tests to verify.</p><p>The loop repeats until the task is complete. The user can interrupt at any point to redirect, provide context, or ask Claude to try a different approach.</p><h2 id="the-loop-in-detail" tabindex="-1">The Loop in Detail <a class="header-anchor" href="#the-loop-in-detail" aria-label="Permalink to &quot;The Loop in Detail&quot;">​</a></h2>',6)),(o(),n(l,null,{default:t(()=>[r(s,{id:"mermaid-20",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22USER%20PROMPT%3Cbr%2F%3E'Fix%20the%20failing%20tests%20in%20src%2Fauth%2F'%22%5D%0A%20%20%20%20B%5B%221.%20GATHER%20CONTEXT%3Cbr%2F%3E%E2%80%A2%20Read%20CLAUDE.md%20%2B%20auto-memory%3Cbr%2F%3E%E2%80%A2%20Search%2Fgrep%20for%20relevant%20files%3Cbr%2F%3E%E2%80%A2%20Read%20source%20files%20to%20understand%20code%3Cbr%2F%3E%E2%80%A2%20Run%20tests%20to%20see%20what's%20failing%3Cbr%2F%3E%E2%80%A2%20Examine%20error%20output%3Cbr%2F%3E%3Cbr%2F%3ETools%3A%20Read%2C%20Grep%2C%20Glob%2C%20Bash%2C%20WebFetch%22%5D%0A%20%20%20%20C%5B%222.%20TAKE%20ACTION%3Cbr%2F%3E%E2%80%A2%20Edit%20source%20files%20to%20fix%20issues%3Cbr%2F%3E%E2%80%A2%20Write%20new%20files%20if%20needed%3Cbr%2F%3E%E2%80%A2%20Run%20commands%20(build%2C%20install%20deps)%3Cbr%2F%3E%E2%80%A2%20Create%2Fmodify%20configs%3Cbr%2F%3E%3Cbr%2F%3ETools%3A%20Edit%2C%20Write%2C%20Bash%2C%20NotebookEdit%22%5D%0A%20%20%20%20D%5B%223.%20VERIFY%20RESULTS%3Cbr%2F%3E%E2%80%A2%20Run%20test%20suite%20again%3Cbr%2F%3E%E2%80%A2%20Check%20for%20type%20errors%20via%20LSP%3Cbr%2F%3E%E2%80%A2%20Run%20linters%3Cbr%2F%3E%E2%80%A2%20Compare%20before%2Fafter%3Cbr%2F%3E%E2%80%A2%20Search%20for%20related%20issues%3Cbr%2F%3E%3Cbr%2F%3ETools%3A%20Bash%2C%20Read%2C%20Grep%2C%20LSP%22%5D%0A%20%20%20%20E%7BTask%20done%3F%7D%0A%20%20%20%20F%5B%22RESPOND%20TO%20USER%3Cbr%2F%3ESummary%20of%20what%20was%20done%2C%20results%22%5D%0A%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%20--%3E%20E%0A%20%20%20%20E%20--%20No%20--%3E%20B%0A%20%20%20%20E%20--%20Yes%20--%3E%20F%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h2 id="phase-behavior" tabindex="-1">Phase Behavior <a class="header-anchor" href="#phase-behavior" aria-label="Permalink to &quot;Phase Behavior&quot;">​</a></h2><h3 id="adaptive-phase-selection" tabindex="-1">Adaptive Phase Selection <a class="header-anchor" href="#adaptive-phase-selection" aria-label="Permalink to &quot;Adaptive Phase Selection&quot;">​</a></h3><p>The loop adapts to the task type:</p><ul><li><strong>Question about codebase</strong>: Mostly context gathering — search, read, then respond</li><li><strong>Bug fix</strong>: Full cycle — find the bug, fix it, verify the fix, possibly iterate</li><li><strong>Refactoring</strong>: Heavy verification — make changes, run tests, check for regressions</li><li><strong>Code review</strong>: Context gathering + analysis — read code, identify issues, report</li><li><strong>PR creation</strong>: Action-heavy — stage changes, craft commit messages, push</li></ul><h3 id="tool-chaining" tabindex="-1">Tool Chaining <a class="header-anchor" href="#tool-chaining" aria-label="Permalink to &quot;Tool Chaining&quot;">​</a></h3><p>Claude chains dozens of tool calls together within a single turn, course-correcting based on what it learns:</p><ol><li><code>Grep(&quot;error message&quot;)</code> → finds the relevant file</li><li><code>Read(&quot;src/auth/session.ts&quot;)</code> → understands the code</li><li><code>Bash(&quot;npm test -- --grep &#39;session&#39;&quot;)</code> → sees the failing test</li><li><code>Edit(&quot;src/auth/session.ts&quot;, ...)</code> → fixes the issue</li><li><code>Bash(&quot;npm test -- --grep &#39;session&#39;&quot;)</code> → verifies the fix passes</li><li>Continue or respond based on result</li></ol><p>Each tool use returns information that feeds back into the loop, informing the next decision.</p><h2 id="model-selection-and-reasoning" tabindex="-1">Model Selection and Reasoning <a class="header-anchor" href="#model-selection-and-reasoning" aria-label="Permalink to &quot;Model Selection and Reasoning&quot;">​</a></h2><h3 id="available-models" tabindex="-1">Available Models <a class="header-anchor" href="#available-models" aria-label="Permalink to &quot;Available Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Strengths</th><th>Typical Use</th></tr></thead><tbody><tr><td><strong>Sonnet</strong></td><td>Fast, cost-effective</td><td>Most coding tasks, everyday use</td></tr><tr><td><strong>Opus</strong></td><td>Strongest reasoning</td><td>Complex architecture, difficult bugs</td></tr><tr><td><strong>Haiku</strong></td><td>Fastest, cheapest</td><td>Used by Explore sub-agent, quick tasks</td></tr></tbody></table><p>Users can switch models mid-session with <code>/model</code> or start with <code>claude --model &lt;name&gt;</code>.</p><h3 id="extended-thinking" tabindex="-1">Extended Thinking <a class="header-anchor" href="#extended-thinking" aria-label="Permalink to &quot;Extended Thinking&quot;">​</a></h3><p>Extended thinking is enabled by default, giving Claude space to reason through complex problems before responding:</p><ul><li><strong>Opus 4.6 / Sonnet 4.6</strong>: Adaptive reasoning — dynamically allocates thinking tokens based on effort level</li><li><strong>Older models</strong>: Fixed thinking token budget</li><li><strong>Effort levels</strong>: <code>/effort low|medium|high</code> controls thinking depth</li><li><strong>&quot;ultrathink&quot; keyword</strong>: Include in prompt for maximum thinking on a single turn</li><li><strong>Visible reasoning</strong>: Press <code>Ctrl+O</code> to toggle verbose mode and see thinking as gray italic text</li></ul><h2 id="user-interaction-points" tabindex="-1">User Interaction Points <a class="header-anchor" href="#user-interaction-points" aria-label="Permalink to &quot;User Interaction Points&quot;">​</a></h2><p>The user is part of the loop. Key interaction mechanisms:</p><h3 id="interruption" tabindex="-1">Interruption <a class="header-anchor" href="#interruption" aria-label="Permalink to &quot;Interruption&quot;">​</a></h3><ul><li><strong><code>Esc</code></strong>: Stop mid-action, context preserved, redirect immediately</li><li><strong>Type while Claude works</strong>: Claude sees your message and adjusts approach</li><li>No need to wait for completion — just type corrections</li></ul><h3 id="rewind-undo" tabindex="-1">Rewind / Undo <a class="header-anchor" href="#rewind-undo" aria-label="Permalink to &quot;Rewind / Undo&quot;">​</a></h3><ul><li><strong><code>Esc + Esc</code> or <code>/rewind</code></strong>: Open rewind menu — restore conversation, code, or both to any checkpoint</li><li><strong>&quot;Undo that&quot;</strong>: Claude reverts its changes</li><li>Checkpoints persist across sessions — close terminal, rewind later</li></ul><h3 id="context-reset" tabindex="-1">Context Reset <a class="header-anchor" href="#context-reset" aria-label="Permalink to &quot;Context Reset&quot;">​</a></h3><ul><li><strong><code>/clear</code></strong>: Wipe conversation context between unrelated tasks</li><li>Clean context with better prompt &gt; long session with accumulated corrections</li></ul><h3 id="permission-mode-cycling" tabindex="-1">Permission Mode Cycling <a class="header-anchor" href="#permission-mode-cycling" aria-label="Permalink to &quot;Permission Mode Cycling&quot;">​</a></h3><ul><li><strong><code>Shift+Tab</code></strong>: Cycle through default → auto-accept edits → plan mode</li><li>Plan mode: Read-only analysis, no modifications until you approve</li></ul><h2 id="sub-agent-delegation" tabindex="-1">Sub-Agent Delegation <a class="header-anchor" href="#sub-agent-delegation" aria-label="Permalink to &quot;Sub-Agent Delegation&quot;">​</a></h2><p>Claude can delegate work to sub-agents that run in separate context windows:</p><h3 id="built-in-sub-agents" tabindex="-1">Built-in Sub-Agents <a class="header-anchor" href="#built-in-sub-agents" aria-label="Permalink to &quot;Built-in Sub-Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Purpose</th><th>Tools</th></tr></thead><tbody><tr><td><strong>Explore</strong></td><td>Haiku</td><td>Codebase search/analysis</td><td>Read-only (Read, Grep, Glob)</td></tr><tr><td><strong>Plan</strong></td><td>Inherits</td><td>Research for plan mode</td><td>Read-only</td></tr><tr><td><strong>General-purpose</strong></td><td>Inherits</td><td>Complex multi-step tasks</td><td>All tools</td></tr></tbody></table><h3 id="delegation-flow" tabindex="-1">Delegation Flow <a class="header-anchor" href="#delegation-flow" aria-label="Permalink to &quot;Delegation Flow&quot;">​</a></h3>',30)),(o(),n(l,null,{default:t(()=>[r(s,{id:"mermaid-340",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Main%20Loop%22%5D%0A%20%20%20%20B%5B%22Sub-agent%3Cbr%2F%3E(separate%20context%20window%2C%20own%20tool%20calls)%22%5D%0A%0A%20%20%20%20A%20--%3E%7C%22Spawns%20sub-agent%20with%20task%20description%22%7C%20B%0A%20%20%20%20B%20--%3E%7C%22Returns%20summary%3Cbr%2F%3E(exploration%20results%20don't%20clutter%20main%20context)%22%7C%20A%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a(`<p>Key constraint: <strong>Sub-agents cannot spawn other sub-agents</strong> — this prevents infinite nesting.</p><h3 id="when-claude-delegates" tabindex="-1">When Claude Delegates <a class="header-anchor" href="#when-claude-delegates" aria-label="Permalink to &quot;When Claude Delegates&quot;">​</a></h3><p>Claude delegates to sub-agents when:</p><ul><li><strong>Exploration</strong>: Needs to read many files without cluttering main context (→ Explore)</li><li><strong>Planning</strong>: In plan mode, needs to research codebase (→ Plan)</li><li><strong>Complex tasks</strong>: Needs both exploration and modification with complex reasoning (→ General-purpose)</li><li><strong>User explicitly asks</strong>: &quot;Use a sub-agent to review this code&quot;</li></ul><h2 id="headless-non-interactive-mode" tabindex="-1">Headless / Non-Interactive Mode <a class="header-anchor" href="#headless-non-interactive-mode" aria-label="Permalink to &quot;Headless / Non-Interactive Mode&quot;">​</a></h2><p>Claude Code can run without user interaction:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Single prompt, no interactive session</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">claude</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;explain the auth system&quot;</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#A6E3A1;"> output.txt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Piped input</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cat</span><span style="color:#A6E3A1;"> error.log</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> claude</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;explain this error&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Plan mode headless</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">claude</span><span style="color:#A6E3A1;"> --permission-mode</span><span style="color:#A6E3A1;"> plan</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;analyze the authentication system&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># JSON output</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">claude</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;list all API endpoints&quot;</span><span style="color:#A6E3A1;"> --output-format</span><span style="color:#A6E3A1;"> json</span></span></code></pre></div><p>In headless mode, the agentic loop runs autonomously — no permission prompts (depending on mode), no user interruption points. Used for CI/CD integration, scripting, and automation.</p><h2 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h2><ol><li><p><strong>The loop is not fixed-step</strong>: Claude doesn&#39;t follow a rigid gather→act→verify pipeline. It dynamically decides what each step requires. A simple question may need only one read; a complex bug fix may cycle through all phases multiple times.</p></li><li><p><strong>Verification is the key to quality</strong>: Anthropic&#39;s best practices emphasize that Claude performs &quot;dramatically better&quot; when it can verify its own work — tests, linters, screenshots. Without verification criteria, the user becomes the only feedback loop.</p></li><li><p><strong>Context accumulation is the enemy</strong>: Every tool call (file reads, command outputs) adds to context. The loop must be efficient — unnecessary reads degrade performance. This is why sub-agents are critical for exploration.</p></li><li><p><strong>The user is always in the loop</strong>: Despite being &quot;agentic,&quot; Claude Code is designed for human oversight. Esc to interrupt, Shift+Tab to restrict, checkpoints to rewind. The loop never fully escapes user control.</p></li><li><p><strong>Model choice affects loop behavior</strong>: Opus reasons more deeply but is slower; Sonnet is faster for routine tasks; Haiku is fastest for exploration sub-agents. The choice of model shapes how many iterations the loop needs.</p></li></ol>`,10))])}const E=d(h,[["render",u]]);export{A as __pageData,E as default};
